import {Activity, Client, GuildChannel} from "discord.js";
import {createLogger} from "../utils/logger";
import {EnvConfig} from "../utils/envConfig";

const logger = createLogger("MinecraftOnlineChannelService");

const DEFAULT_STATUS_SOURCE_USER_ID = "1482105326021906432";
const DEFAULT_CHANNEL_ID = "1481902621005713530";

const RATE_LIMIT_WINDOW_MS = 10 * 60 * 1000;
const MAX_RENAMES_PER_WINDOW = 2;
const RATE_LIMIT_SAFETY_MS = 1000;

const renameTimestamps: number[] = [];
let pendingName: string | null = null;
let pendingRenameTimer: NodeJS.Timeout | null = null;

function extractOnlinePlayersFromActivities(activities: readonly Activity[]): number | null {
    const patterns = [
        /(\d+)\s*\/\s*\d+\s*(?:in simulation?|players?)/i,
        /(?:online|en\s+ligne)\s*[:\-]?\s*(\d+)/i,
        /(\d+)\s*(?:in simulation?|players?)\s*(?:online|en\s+ligne)?/i,
    ];

    for (const activity of activities) {
        const candidates = [activity.name, activity.state, activity.details];
        for (const value of candidates) {
            if (!value) continue;
            for (const pattern of patterns) {
                const match = value.match(pattern);
                if (!match) continue;
                const onlinePlayers = parseInt(match[1], 10);
                if (!Number.isNaN(onlinePlayers) && onlinePlayers >= 0) {
                    return onlinePlayers;
                }
            }
        }
    }

    return null;
}

async function updateMinecraftOnlineChannel(client: Client, onlinePlayers: number): Promise<void> {
    const expectedName = ` En ligne : ${onlinePlayers}`;
    await tryRenameMinecraftChannel(client, expectedName);
}

function pruneRenameTimestamps(now: number): void {
    while (renameTimestamps.length > 0 && now - renameTimestamps[0] >= RATE_LIMIT_WINDOW_MS) {
        renameTimestamps.shift();
    }
}

function getRequiredDelayBeforeRename(now: number): number {
    pruneRenameTimestamps(now);

    if (renameTimestamps.length < MAX_RENAMES_PER_WINDOW) {
        return 0;
    }

    const oldestRenameTs = renameTimestamps[0];
    return Math.max(0, (oldestRenameTs + RATE_LIMIT_WINDOW_MS + RATE_LIMIT_SAFETY_MS) - now);
}

function recordRename(now: number): void {
    renameTimestamps.push(now);
    pruneRenameTimestamps(now);
}

async function getTargetGuildChannel(client: Client): Promise<GuildChannel | null> {
    const channelId = EnvConfig.MINECRAFT_ONLINE_CHANNEL_ID || DEFAULT_CHANNEL_ID;

    const channel = await client.channels.fetch(channelId);
    if (!channel) {
        logger.warn(`[Minecraft] Channel ${channelId} introuvable`);
        return null;
    }

    if (!("guild" in channel) || typeof (channel as any).setName !== "function") {
        logger.warn(`[Minecraft] Channel ${channelId} n'est pas renommable`);
        return null;
    }

    return channel as GuildChannel;
}

async function resolveOnlinePlayersFromSourcePresence(client: Client): Promise<number | null> {
    const guildChannel = await getTargetGuildChannel(client);
    if (!guildChannel) return null;

    const sourceUserId = EnvConfig.MINECRAFT_STATUS_SOURCE_USER_ID || DEFAULT_STATUS_SOURCE_USER_ID;
    const sourceMember = await guildChannel.guild.members.fetch(sourceUserId).catch(() => null);
    if (!sourceMember) {
        logger.warn(`[Minecraft] Source presence introuvable (userId: ${sourceUserId})`);
        return null;
    }

    const activities = sourceMember.presence?.activities ?? [];
    if (activities.length === 0) {
        logger.warn(`[Minecraft] Aucune activité de présence détectée pour ${sourceMember.user.username} (${sourceUserId})`);
        return null;
    }

    const onlinePlayers = extractOnlinePlayersFromActivities(activities);
    if (onlinePlayers === null) {
        logger.warn(`[Minecraft] Impossible d'extraire X depuis les activités de présence de ${sourceMember.user.username}`);
        return null;
    }

    return onlinePlayers;
}

function schedulePendingRename(client: Client, delayMs: number): void {
    if (pendingRenameTimer) return;

    pendingRenameTimer = setTimeout(() => {
        pendingRenameTimer = null;
        void flushPendingRename(client);
    }, delayMs);
}

async function flushPendingRename(client: Client): Promise<void> {
    if (!pendingName) return;

    const nextName = pendingName;
    pendingName = null;

    const guildChannel = await getTargetGuildChannel(client);
    if (!guildChannel) return;
    if (guildChannel.name === nextName) return;

    const now = Date.now();
    const delay = getRequiredDelayBeforeRename(now);
    if (delay > 0) {
        pendingName = nextName;
        schedulePendingRename(client, delay);
        return;
    }

    await guildChannel.setName(nextName);
    recordRename(Date.now());
    logger.info(`[Minecraft] Salon renommé: ${nextName}`);
}

async function tryRenameMinecraftChannel(client: Client, expectedName: string): Promise<void> {
    const guildChannel = await getTargetGuildChannel(client);
    if (!guildChannel) return;

    if (guildChannel.name === expectedName) return;

    const now = Date.now();
    const delay = getRequiredDelayBeforeRename(now);
    if (delay > 0) {
        pendingName = expectedName;
        schedulePendingRename(client, delay);
        logger.info(`[Minecraft] Rename différé pour respecter la limite Discord (dans ${Math.ceil(delay / 1000)}s)`);
        return;
    }

    await guildChannel.setName(expectedName);
    recordRename(now);
    logger.info(`[Minecraft] Salon renommé: ${expectedName}`);
}

export function startMinecraftOnlineChannelUpdater(client: Client): void {
    const intervalMs = EnvConfig.MINECRAFT_ONLINE_UPDATE_INTERVAL_MS;

    if (intervalMs <= 0) {
        logger.warn("[Minecraft] Updater désactivé (interval <= 0)");
        return;
    }

    const tick = async () => {
        try {
            const onlinePlayers = await resolveOnlinePlayersFromSourcePresence(client);
            if (onlinePlayers === null) return;
            await updateMinecraftOnlineChannel(client, onlinePlayers);
        } catch (error) {
            logger.warn("[Minecraft] Erreur pendant la mise à jour du salon:", error);
        }
    };

    void tick();
    setInterval(() => {
        void tick();
    }, intervalMs);

    logger.info(`[Minecraft] Updater démarré (interval ${intervalMs / 1000}s)`);
}

import {Activity, Client, GuildChannel} from "discord.js";
import {createLogger} from "../utils/logger";
import {EnvConfig} from "../utils/envConfig";
import {Rcon} from "rcon-client";

const logger = createLogger("MinecraftOnlineChannelService");

const DEFAULT_STATUS_SOURCE_USER_ID = "1482105326021906432";
const DEFAULT_CHANNEL_ID = "1481902621005713530";

const RATE_LIMIT_WINDOW_MS = 10 * 60 * 1000;
const MAX_RENAMES_PER_WINDOW = 2;
const RATE_LIMIT_SAFETY_MS = 1000;

const renameTimestamps: number[] = [];
let pendingName: string | null = null;
let pendingRenameTimer: NodeJS.Timeout | null = null;

type OnlineSnapshot = {
    onlinePlayers: number;
    players: string[];
};

function extractOnlinePlayersFromActivities(activities: readonly Activity[]): number | null {
    const patterns = [
        /(\d+)\s*\/\s*\d+\s*(?:in simulation?|players?)/i,
        /(?:online|en\s+ligne)\s*[:\-]?\s*(\d+)/i,
        /(\d+)\s*(?:in simulation?|players?)\s*(?:online|en\s+ligne)?/i,
    ];

    for (const activity of activities) {
        const candidates = [activity.name, activity.state, activity.details];
        for (const value of candidates) {
            if (!value) continue;
            for (const pattern of patterns) {
                const match = value.match(pattern);
                if (!match) continue;
                const onlinePlayers = parseInt(match[1], 10);
                if (!Number.isNaN(onlinePlayers) && onlinePlayers >= 0) {
                    return onlinePlayers;
                }
            }
        }
    }

    return null;
}

async function updateMinecraftOnlineChannel(client: Client, onlinePlayers: number): Promise<void> {
    const expectedName = ` En ligne : ${onlinePlayers}`;
    await tryRenameMinecraftChannel(client, expectedName);
}

function buildPlayersTopic(snapshot: OnlineSnapshot): string {
    if (snapshot.onlinePlayers <= 0) {
        return "Joueurs en ligne (0) : personne";
    }

    if (snapshot.players.length === 0) {
        return `Joueurs en ligne (${snapshot.onlinePlayers})`;
    }

    const base = `Joueurs en ligne (${snapshot.onlinePlayers}) : `;
    const joinedPlayers = snapshot.players.join(", ");
    const maxLength = 1024;
    const rawTopic = `${base}${joinedPlayers}`;

    if (rawTopic.length <= maxLength) {
        return rawTopic;
    }

    return `${rawTopic.slice(0, maxLength - 3)}...`;
}

async function updateMinecraftPlayersTopic(client: Client, snapshot: OnlineSnapshot): Promise<void> {
    const topicChannelId = EnvConfig.MINECRAFT_ONLINE_TOPIC_CHANNEL_ID || EnvConfig.MINECRAFT_ONLINE_CHANNEL_ID || DEFAULT_CHANNEL_ID;
    const channel = await client.channels.fetch(topicChannelId).catch(() => null);

    if (!channel) {
        logger.warn(`[Minecraft] Salon topic ${topicChannelId} introuvable`);
        return;
    }

    if (typeof (channel as any).setTopic !== "function") {
        logger.warn(`[Minecraft] Le salon ${topicChannelId} ne supporte pas setTopic()`);
        return;
    }

    const expectedTopic = buildPlayersTopic(snapshot);
    const currentTopic = typeof (channel as any).topic === "string" ? (channel as any).topic : "";
    if (currentTopic === expectedTopic) {
        return;
    }

    await (channel as any).setTopic(expectedTopic);
}

function parsePlayersFromRconListResponse(response: string): OnlineSnapshot | null {
    const trimmed = response.trim();

    const englishFormat = trimmed.match(/^There are\s+(\d+)\s+of a max of\s+\d+\s+players online:?\s*(.*)$/i);
    if (englishFormat) {
        const onlinePlayers = parseInt(englishFormat[1], 10);
        const playersRaw = englishFormat[2]?.trim() || "";
        const players = playersRaw ? playersRaw.split(",").map(name => name.trim()).filter(Boolean) : [];
        return {onlinePlayers, players};
    }

    const countFallback = trimmed.match(/(\d+)/);
    if (!countFallback) {
        return null;
    }

    const onlinePlayers = parseInt(countFallback[1], 10);
    if (Number.isNaN(onlinePlayers) || onlinePlayers < 0) {
        return null;
    }

    const maybePlayersRaw = trimmed.includes(":") ? trimmed.split(":").slice(1).join(":").trim() : "";
    const players = maybePlayersRaw ? maybePlayersRaw.split(",").map(name => name.trim()).filter(Boolean) : [];

    return {onlinePlayers, players};
}

function pruneRenameTimestamps(now: number): void {
    while (renameTimestamps.length > 0 && now - renameTimestamps[0] >= RATE_LIMIT_WINDOW_MS) {
        renameTimestamps.shift();
    }
}

function getRequiredDelayBeforeRename(now: number): number {
    pruneRenameTimestamps(now);

    if (renameTimestamps.length < MAX_RENAMES_PER_WINDOW) {
        return 0;
    }

    const oldestRenameTs = renameTimestamps[0];
    return Math.max(0, (oldestRenameTs + RATE_LIMIT_WINDOW_MS + RATE_LIMIT_SAFETY_MS) - now);
}

function recordRename(now: number): void {
    renameTimestamps.push(now);
    pruneRenameTimestamps(now);
}

async function getTargetGuildChannel(client: Client): Promise<GuildChannel | null> {
    const channelId = EnvConfig.MINECRAFT_ONLINE_CHANNEL_ID || DEFAULT_CHANNEL_ID;

    const channel = await client.channels.fetch(channelId);
    if (!channel) {
        logger.warn(`[Minecraft] Channel ${channelId} introuvable`);
        return null;
    }

    if (!("guild" in channel) || typeof (channel as any).setName !== "function") {
        logger.warn(`[Minecraft] Channel ${channelId} n'est pas renommable`);
        return null;
    }

    return channel as GuildChannel;
}

async function resolveOnlinePlayersFromSourcePresence(client: Client): Promise<number | null> {
    const guildChannel = await getTargetGuildChannel(client);
    if (!guildChannel) return null;

    const sourceUserId = EnvConfig.MINECRAFT_STATUS_SOURCE_USER_ID || DEFAULT_STATUS_SOURCE_USER_ID;
    const sourceMember = await guildChannel.guild.members.fetch(sourceUserId).catch(() => null);
    if (!sourceMember) {
        logger.warn(`[Minecraft] Source presence introuvable (userId: ${sourceUserId})`);
        return null;
    }

    const activities = sourceMember.presence?.activities ?? [];
    if (activities.length === 0) {
        logger.warn(`[Minecraft] Aucune activité de présence détectée pour ${sourceMember.user.username} (${sourceUserId})`);
        return null;
    }

    const onlinePlayers = extractOnlinePlayersFromActivities(activities);
    if (onlinePlayers === null) {
        logger.warn(`[Minecraft] Impossible d'extraire X depuis les activités de présence de ${sourceMember.user.username}`);
        return null;
    }

    return onlinePlayers;
}

async function resolveOnlineSnapshotFromRcon(): Promise<OnlineSnapshot | null> {
    if (!EnvConfig.MINECRAFT_RCON_PASSWORD) {
        return null;
    }

    const rcon = await Rcon.connect({
        host: EnvConfig.MINECRAFT_RCON_HOST,
        port: EnvConfig.MINECRAFT_RCON_PORT,
        password: EnvConfig.MINECRAFT_RCON_PASSWORD,
        timeout: EnvConfig.MINECRAFT_RCON_TIMEOUT_MS,
    });

    try {
        const response = await rcon.send("list");
        const parsed = parsePlayersFromRconListResponse(response);
        if (!parsed) {
            logger.warn(`[Minecraft] Réponse RCON inattendue pour 'list': ${response}`);
            return null;
        }
        return parsed;
    } finally {
        await rcon.end().catch(() => undefined);
    }
}

function schedulePendingRename(client: Client, delayMs: number): void {
    if (pendingRenameTimer) return;

    pendingRenameTimer = setTimeout(() => {
        pendingRenameTimer = null;
        void flushPendingRename(client);
    }, delayMs);
}

async function flushPendingRename(client: Client): Promise<void> {
    if (!pendingName) return;

    const nextName = pendingName;
    pendingName = null;

    const guildChannel = await getTargetGuildChannel(client);
    if (!guildChannel) return;
    if (guildChannel.name === nextName) return;

    const now = Date.now();
    const delay = getRequiredDelayBeforeRename(now);
    if (delay > 0) {
        pendingName = nextName;
        schedulePendingRename(client, delay);
        return;
    }

    await guildChannel.setName(nextName);
    recordRename(Date.now());
    logger.info(`[Minecraft] Salon renommé: ${nextName}`);
}

async function tryRenameMinecraftChannel(client: Client, expectedName: string): Promise<void> {
    const guildChannel = await getTargetGuildChannel(client);
    if (!guildChannel) return;

    if (guildChannel.name === expectedName) return;

    const now = Date.now();
    const delay = getRequiredDelayBeforeRename(now);
    if (delay > 0) {
        pendingName = expectedName;
        schedulePendingRename(client, delay);
        logger.info(`[Minecraft] Rename différé pour respecter la limite Discord (dans ${Math.ceil(delay / 1000)}s)`);
        return;
    }

    await guildChannel.setName(expectedName);
    recordRename(now);
    logger.info(`[Minecraft] Salon renommé: ${expectedName}`);
}

export function startMinecraftOnlineChannelUpdater(client: Client): void {
    const intervalMs = EnvConfig.MINECRAFT_ONLINE_UPDATE_INTERVAL_MS;

    if (intervalMs <= 0) {
        logger.warn("[Minecraft] Updater désactivé (interval <= 0)");
        return;
    }

    const tick = async () => {
        try {
            let snapshot = await resolveOnlineSnapshotFromRcon().catch((error) => {
                logger.warn("[Minecraft] RCON indisponible, tentative de fallback présence:", error);
                return null;
            });

            if (!snapshot && EnvConfig.MINECRAFT_ONLINE_USE_PRESENCE_FALLBACK) {
                const onlinePlayers = await resolveOnlinePlayersFromSourcePresence(client);
                if (onlinePlayers !== null) {
                    snapshot = {onlinePlayers, players: []};
                }
            }

            if (!snapshot) {
                return;
            }

            await updateMinecraftOnlineChannel(client, snapshot.onlinePlayers);
            await updateMinecraftPlayersTopic(client, snapshot);
        } catch (error) {
            logger.warn("[Minecraft] Erreur pendant la mise à jour du salon:", error);
        }
    };

    void tick();
    setInterval(() => {
        void tick();
    }, intervalMs);

    logger.info(`[Minecraft] Updater démarré (interval ${intervalMs / 1000}s)`);
}

import {createLogger} from "./logger";

const logger = createLogger("EnvConfig");

/**
 * Configuration centralisée des variables d'environnement
 * Toutes les variables d'environnement sont définies et typées ici
 */

export class EnvConfig {
    // Discord Bot Token
    static get DISCORD_BOT_TOKEN(): string {
        return process.env.DISCORD_LLM_BOT_TOKEN || "";
    }

    // Discord Channel IDs
    static get WATCH_CHANNEL_ID(): string | undefined {
        return process.env.WATCH_CHANNEL_ID;
    }

    static get WELCOME_CHANNEL_ID(): string | undefined {
        return process.env.WELCOME_CHANNEL_ID;
    }

    static get LOG_CHANNEL_ID(): string | undefined {
        return process.env.LOG_CHANNEL_ID;
    }

    static get NETRICSA_LOG_CHANNEL_ID(): string | undefined {
        return process.env.NETRICSA_LOG_CHANNEL_ID;
    }

    static get FORUM_CHANNEL_ID(): string | undefined {
        return process.env.FORUM_CHANNEL_ID;
    }

    static get CREATION_FORUM_ID(): string | undefined {
        return process.env.CREATION_FORUM_ID;
    }

    static get MEME_CHANNEL_ID(): string | undefined {
        return process.env.MEME_CHANNEL_ID;
    }

    static get ANNOUNCEMENTS_CHANNEL_ID(): string | undefined {
        return process.env.ANNOUNCEMENTS_CHANNEL_ID;
    }

    static get COUNTER_CHANNEL_ID(): string | undefined {
        return process.env.COUNTER_CHANNEL_ID;
    }

    static get COMMAND_CHANNEL_ID(): string | undefined {
        return process.env.COMMAND_CHANNEL_ID;
    }

    static get GAMES_CHANNEL_ID(): string | undefined {
        return process.env.GAMES_CHANNEL_ID;
    }

    static get DAILY_CHALLENGES_CHANNEL_ID(): string | undefined {
        return process.env.DAILY_CHALLENGES_CHANNEL_ID;
    }

    static get FREE_GAMES_CHANNEL_ID(): string | undefined {
        return process.env.FREE_GAMES_CHANNEL_ID;
    }

    static get MINECRAFT_STATUS_GUILD_ID(): string | undefined {
        return process.env.MINECRAFT_STATUS_GUILD_ID;
    }

    static get MINECRAFT_ONLINE_CHANNEL_ID(): string | undefined {
        return process.env.MINECRAFT_ONLINE_CHANNEL_ID;
    }

    static get MINECRAFT_STATUS_SOURCE_USER_ID(): string | undefined {
        return process.env.MINECRAFT_STATUS_SOURCE_USER_ID;
    }

    static get MINECRAFT_ONLINE_UPDATE_INTERVAL_MS(): number {
        return parseInt(process.env.MINECRAFT_ONLINE_UPDATE_INTERVAL_MS || "60000", 10);
    }

    static get CITATIONS_THREAD_ID(): string | undefined {
        return process.env.CITATIONS_THREAD_ID;
    }

    // Guild/Server ID
    static get GUILD_ID(): string | undefined {
        return process.env.GUILD_ID;
    }

    // Role IDs
    static get BIRTHDAY_ROLE_ID(): string | undefined {
        return process.env.BIRTHDAY_ROLE_ID;
    }

    static get ROLE_REACTION_MESSAGE_ID(): string | undefined {
        return process.env.ROLE_REACTION_MESSAGE_ID;
    }

    static get ROLE_REACTION_ROLE_ID(): string | undefined {
        return process.env.ROLE_REACTION_ROLE_ID;
    }

    static get FREE_GAMES_LOOT_ROLE_ID(): string | undefined {
        return process.env.FREE_GAMES_LOOT_ROLE_ID;
    }

    static get FREE_GAMES_LOOT_EMOJI_ID(): string | undefined {
        return process.env.FREE_GAMES_LOOT_EMOJI_ID;
    }

    static get ROLE_REACTION_EMOJI_ID(): string | undefined {
        return process.env.ROLE_REACTION_EMOJI_ID;
    }

    static get ROLE_REACTION_CHANNEL_ID(): string | undefined {
        return process.env.ROLE_REACTION_CHANNEL_ID;
    }

    // File Paths
    static get SYSTEM_PROMPT_PATH(): string {
        return process.env.SYSTEM_PROMPT_PATH || "./data/system_prompt.txt";
    }

    static get SERVER_PROMPT_PATH(): string {
        // Gardé pour backup, non utilisé dans le code
        return process.env.SERVER_PROMPT_PATH || "./data/server_prompt.txt";
    }

    static get SYSTEM_PROMPT_VISION_PATH(): string {
        return process.env.SYSTEM_PROMPT_VISION_PATH || "./data/system_prompt_vision.txt";
    }

    static get MEMORY_FILE_PATH(): string {
        return process.env.MEMORY_FILE || "./data/memory.json";
    }

    // Ollama Configuration
    static get OLLAMA_TEXT_MODEL(): string {
        return process.env.OLLAMA_TEXT_MODEL || "llama3.1:8b-instruct-q8_0";
    }

    static get OLLAMA_VISION_MODEL(): string {
        return process.env.OLLAMA_VISION_MODEL || "qwen2.5-vl:7b";
    }

    // Memory Configuration
    static get MEMORY_MAX_TURNS(): number {
        return parseInt(process.env.MEMORY_MAX_TURNS || "50", 10);
    }

    // Debug Flags
    static get DEBUG_OLLAMA_RAW(): boolean {
        return process.env.DEBUG_OLLAMA_RAW === "1";
    }

    // API Keys
    static get BRAVE_SEARCH_API_KEY(): string | undefined {
        return process.env.BRAVE_SEARCH_API_KEY;
    }

    static get FREESTUFF_API_KEY(): string | undefined {
        return process.env.FREESTUFF_API_KEY;
    }

    static get FREESTUFF_WEBHOOK_PORT(): number {
        return parseInt(process.env.FREESTUFF_WEBHOOK_PORT || "3000", 10);
    }

    static get WEBHOOK_PUBLIC_URL(): string {
        const port = this.FREESTUFF_WEBHOOK_PORT;
        return process.env.WEBHOOK_PUBLIC_URL || `http://localhost:${port}`;
    }

    // ── Nexa (bot de musique)
    static get NEXA_TOKEN(): string | undefined {
        return process.env.NEXA_TOKEN;
    }

    static get NEXA_CLIENT_ID(): string | undefined {
        return process.env.NEXA_CLIENT_ID;
    }

    /** ID du salon dédié musique (texte + requêtes) */
    static get NEXA_MUSIC_CHANNEL_ID(): string | undefined {
        return process.env.NEXA_MUSIC_CHANNEL_ID;
    }

    /** Cookie YouTube optionnel pour contourner les restrictions anti-bot */
    static get YOUTUBE_COOKIE(): string | undefined {
        return process.env.YOUTUBE_COOKIE;
    }

    // Meme Subreddits
    static get MEME_SUBREDDITS(): string[] {
        const subreddits = process.env.MEME_SUBREDDITS || "shitposting";
        return subreddits.split(',').map(s => s.trim());
    }

    /**
     * Valide que toutes les variables d'environnement requises sont présentes
     */
    static validate(): { valid: boolean; missing: string[] } {
        const missing: string[] = [];

        if (!this.DISCORD_BOT_TOKEN) missing.push("DISCORD_LLM_BOT_TOKEN");
        if (!this.SYSTEM_PROMPT_PATH) missing.push("SYSTEM_PROMPT_PATH");
        // SERVER_PROMPT_PATH retiré - non utilisé (gardé en backup seulement)

        return {
            valid: missing.length === 0,
            missing
        };
    }

    /**
     * Affiche un résumé de la configuration
     */
    static printSummary(): void {
        logger.info("=== Configuration Environment ===");
        logger.info(`Watch Channel: ${this.WATCH_CHANNEL_ID || "Not configured"}`);
        logger.info(`Welcome Channel: ${this.WELCOME_CHANNEL_ID || "Not configured"}`);
        logger.info(`Log Channel: ${this.LOG_CHANNEL_ID || "Not configured"}`);
        logger.info(`Forum Channel: ${this.FORUM_CHANNEL_ID || "Not configured"}`);
        logger.info(`Meme Channel: ${this.MEME_CHANNEL_ID || "Not configured"}`);
        logger.info(`Guild ID: ${this.GUILD_ID || "Not configured"}`);
        logger.info(`Birthday Role: ${this.BIRTHDAY_ROLE_ID || "Not configured"}`);
        logger.info(`Ollama Text Model: ${this.OLLAMA_TEXT_MODEL}`);
        logger.info(`Ollama Vision Model: ${this.OLLAMA_VISION_MODEL}`);
        logger.info(`Memory Max Turns: ${this.MEMORY_MAX_TURNS}`);
        logger.info(`Meme Subreddits: ${this.MEME_SUBREDDITS.join(", ")}`);
        logger.info("================================");
    }
}

import {createLogger} from "./logger";

const logger = createLogger("EnvConfig");

/**
 * Configuration centralisée des variables d'environnement
 * Toutes les variables d'environnement sont définies et typées ici
 */

export class EnvConfig {
    // Discord Bot Token
    static get DISCORD_BOT_TOKEN(): string {
        return process.env.DISCORD_LLM_BOT_TOKEN || "";
    }

    // Discord Channel IDs
    static get WATCH_CHANNEL_ID(): string | undefined {
        return process.env.WATCH_CHANNEL_ID;
    }

    static get WELCOME_CHANNEL_ID(): string | undefined {
